import{_ as a,o as i,c as o,ag as e}from"./chunks/framework.BZohXCq9.js";const s=JSON.parse('{"title":"MailYou 隐私政策","description":"","frontmatter":{},"headers":[],"relativePath":"zh/legal/privacy-policy.md","filePath":"zh/legal/privacy-policy.md","lastUpdated":1773655718000}'),t={name:"zh/legal/privacy-policy.md"};function h(r,l,u,p,d,n){return i(),o("div",null,[...l[0]||(l[0]=[e('<h1 id="mailyou-隐私政策" tabindex="-1">MailYou 隐私政策 <a class="header-anchor" href="#mailyou-隐私政策" aria-label="Permalink to &quot;MailYou 隐私政策&quot;">​</a></h1><p>生效日期：2026-03-16</p><p>本隐私政策适用于 MailYou 桌面应用及其相关 OAuth 登录能力。MailYou 是一款桌面邮件客户端，用于帮助用户在本地设备上接入和管理电子邮件账户。</p><p>如果你使用 Gmail、Google 账号登录或其他由 Google API 提供的能力，本政策也适用于 MailYou 对 Google 用户数据的访问、使用、存储、共享和删除方式。</p><h2 id="_1-我们收集和处理的信息" tabindex="-1">1. 我们收集和处理的信息 <a class="header-anchor" href="#_1-我们收集和处理的信息" aria-label="Permalink to &quot;1. 我们收集和处理的信息&quot;">​</a></h2><p>MailYou 可能处理以下信息：</p><ul><li>账户基础信息：邮箱地址、显示名称、服务商类型、服务器地址、协议类型、同步设置。</li><li>登录与认证信息：OAuth 授权得到的访问令牌、刷新令牌，或你自行配置的邮箱账号密码 / 应用专用密码。</li><li>邮件数据：邮件头、发件人、收件人、主题、正文、附件、文件夹信息、已读/未读、星标等状态。</li><li>联系人数据：你在 MailYou 中创建、导入、编辑或保存的联系人信息与头像。</li><li>本地运行数据：应用设置、本地缓存、日志输出，以及为实现同步、发送、草稿保存所需的本地数据。</li></ul><h2 id="_2-我们如何使用这些信息" tabindex="-1">2. 我们如何使用这些信息 <a class="header-anchor" href="#_2-我们如何使用这些信息" aria-label="Permalink to &quot;2. 我们如何使用这些信息&quot;">​</a></h2><p>MailYou 仅将上述信息用于以下目的：</p><ul><li>连接你的邮箱账户并完成身份认证。</li><li>拉取、显示、搜索、发送、保存和同步邮件。</li><li>维护本地草稿、联系人、账户配置和应用设置。</li><li>刷新 OAuth 令牌，维持你已授权账户的持续登录状态。</li><li>排查故障、改进兼容性和提升桌面应用稳定性。</li></ul><p>我们不会将你的 Google 用户数据或邮件内容用于广告投放、用户画像、出售数据，或与本应用核心功能无关的用途。</p><h2 id="_3-google-用户数据的访问与使用" tabindex="-1">3. Google 用户数据的访问与使用 <a class="header-anchor" href="#_3-google-用户数据的访问与使用" aria-label="Permalink to &quot;3. Google 用户数据的访问与使用&quot;">​</a></h2><p>当你选择通过 Google 账号接入 Gmail 时，MailYou 仅在你主动授权后访问完成邮件功能所必需的数据。</p><p>对于 Google 用户数据，MailYou 的处理原则如下：</p><ul><li>访问范围仅限于实现 Gmail 邮件收发、账户接入和令牌刷新所需的范围。</li><li>使用目的仅限于用户明确请求的邮件客户端功能。</li><li>不会将 Google 用户数据出售给第三方。</li><li>不会将 Google 用户数据用于投放广告，包括个性化广告。</li><li>不会将 Google 用户数据提供给数据经纪商。</li></ul><p>MailYou 对 Google API Services 用户数据的使用和传输将遵守 Google API Services User Data Policy，包括 Limited Use 要求。</p><h2 id="_4-数据存储方式" tabindex="-1">4. 数据存储方式 <a class="header-anchor" href="#_4-数据存储方式" aria-label="Permalink to &quot;4. 数据存储方式&quot;">​</a></h2><p>MailYou 以本地优先方式运行。大部分账户配置、邮件缓存、联系人、草稿及应用设置默认保存在你的设备本地。</p><p>OAuth 场景下：</p><ul><li>如果你使用本地直连 OAuth，认证流程直接使用你本地环境变量中配置的客户端凭据完成。</li><li>如果你使用 MailYou OAuth 代理，代理仅用于完成 OAuth 授权地址生成、令牌交换和令牌刷新等必要流程。</li></ul><h2 id="_5-oauth-代理的作用" tabindex="-1">5. OAuth 代理的作用 <a class="header-anchor" href="#_5-oauth-代理的作用" aria-label="Permalink to &quot;5. OAuth 代理的作用&quot;">​</a></h2><p>当你使用 MailYou OAuth 代理时，代理可能临时处理以下信息：</p><ul><li>OAuth 提供方标识</li><li>授权码</li><li>PKCE 相关参数</li><li>访问令牌与刷新令牌</li></ul><p>这些信息仅用于完成授权、换取令牌或刷新令牌，不应用于广告、分析、画像或与你请求无关的其他目的。</p><h2 id="_6-数据共享与披露" tabindex="-1">6. 数据共享与披露 <a class="header-anchor" href="#_6-数据共享与披露" aria-label="Permalink to &quot;6. 数据共享与披露&quot;">​</a></h2><p>除以下情形外，我们不会主动向第三方共享你的个人信息或 Google 用户数据：</p><ul><li>为实现你主动请求的邮箱登录、邮件同步或令牌刷新，需要与你选择的邮箱服务商或 OAuth 提供商交互。</li><li>为实现 OAuth 代理流程，需要与你选择使用的 MailYou OAuth 代理交互。</li><li>法律法规、司法程序或监管机关要求披露。</li><li>为保护用户、开发者或公众的合法权益，有必要披露。</li></ul><h2 id="_7-数据保留与删除" tabindex="-1">7. 数据保留与删除 <a class="header-anchor" href="#_7-数据保留与删除" aria-label="Permalink to &quot;7. 数据保留与删除&quot;">​</a></h2><p>你可以通过以下方式删除数据：</p><ul><li>在 MailYou 中删除账户、联系人、草稿或相关本地数据。</li><li>删除应用本地数据目录。</li><li>在 Google 账户安全设置中撤销对 MailYou 的 OAuth 授权。</li></ul><p>当你删除账户或本地数据后，MailYou 将不再继续使用相应本地数据。若你已授予 Google OAuth 权限，也可通过 Google 提供的权限管理页面撤销授权。</p><h2 id="_8-数据安全" tabindex="-1">8. 数据安全 <a class="header-anchor" href="#_8-数据安全" aria-label="Permalink to &quot;8. 数据安全&quot;">​</a></h2><p>我们采取合理的技术和组织措施保护数据安全，包括但不限于：</p><ul><li>本地存储优先，减少不必要的远程传输。</li><li>仅在完成认证、同步、发送邮件等必要场景下处理数据。</li><li>将 OAuth 令牌使用限制在邮件客户端功能范围内。</li></ul><p>但请理解，任何软件、网络传输或本地设备都无法保证绝对安全。</p><h2 id="_9-儿童隐私" tabindex="-1">9. 儿童隐私 <a class="header-anchor" href="#_9-儿童隐私" aria-label="Permalink to &quot;9. 儿童隐私&quot;">​</a></h2><p>MailYou 不面向儿童提供服务，也不以主动收集儿童个人信息为目的。</p><h2 id="_10-政策更新" tabindex="-1">10. 政策更新 <a class="header-anchor" href="#_10-政策更新" aria-label="Permalink to &quot;10. 政策更新&quot;">​</a></h2><p>我们可能根据产品功能调整、法律要求或 Google API 政策变化更新本隐私政策。更新后的版本将通过公开页面发布，并以新的生效日期为准。</p><h2 id="_11-联系方式" tabindex="-1">11. 联系方式 <a class="header-anchor" href="#_11-联系方式" aria-label="Permalink to &quot;11. 联系方式&quot;">​</a></h2><p>如果你对本隐私政策有疑问，或希望就数据访问、删除、纠正等事项与我们联系，请发送邮件至：</p><p><code>4hhhhfor@gmail.com</code></p>',42)])])}const _=a(t,[["render",h]]);export{s as __pageData,_ as default};
